#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool = ev.get("tool_name", "")
    inp  = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "")

    # Block bare `pnpm test` but allow `pnpm test:ci` or other variants
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd:
        print("Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and won't return.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Write/Edit to .py files, run ruff format and feed results back."""
import json, subprocess, sys, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Write", "Edit"):
        return 0

    inp = ev.get("tool_input") or {}
    fpath = inp.get("file_path", "")

    if not fpath.endswith(".py"):
        return 0

    try:
        r = subprocess.run(
            ["ruff", "format", fpath],
            capture_output=True,
            text=True,
            timeout=10,
            cwd=os.environ.get("CLAUDE_PROJECT_DIR", ".")
        )
        if r.returncode != 0 and r.stderr:
            print(f"REQUIRED FOLLOW-UP: ruff format failed on {fpath}:", file=sys.stderr)
            print(r.stderr, file=sys.stderr)
            print("Fix the formatting issue, then proceed. Do not stop.", file=sys.stderr)
            return 2
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

