#!/usr/bin/env python3
import json, sys, subprocess, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    if not os.path.isfile(file_path):
        return 0

    # Run pyflakes to catch undefined names
    result = subprocess.run(
        ["python3", "-m", "pyflakes", file_path],
        capture_output=True,
        text=True,
        timeout=5
    )

    if result.returncode != 0 and "undefined name" in result.stdout:
        print(f"REQUIRED FOLLOW-UP: pyflakes found undefined variables in {file_path}:\n{result.stdout.strip()}\nFix each undefined name before proceeding.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())
